 79→// Reads an integer at the current offset, in big-endian order, and advances
 80→// the offset on success. Throws if reading the integer would move the
 81→// offset past the end of the buffer.
 82→fileprivate func readInt<T: FixedWidthInteger>(_ reader: inout (data: Data, offset: Data.Index)) throws -> T {
 83→    let range = reader.offset..<reader.offset + MemoryLayout<T>.size
 84→    guard reader.data.count >= range.upperBound else {
 85→        throw UniffiInternalError.bufferOverflow
 86→    }
 87→    if T.self == UInt8.self {
 88→        let value = reader.data[reader.offset]
 89→        reader.offset += 1
 90→        return value as! T
 91→    }
 92→    var value: T = 0
 93→    let _ = withUnsafeMutableBytes(of: &value, { reader.data.copyBytes(to: $0, from: range)})
 94→    reader.offset = range.upperBound
 95→    return value.bigEndian
 96→}
