 98→// Reads an arbitrary number of bytes, to be used to read
 99→// raw bytes, this is useful when lifting strings
100→fileprivate func readBytes(_ reader: inout (data: Data, offset: Data.Index), count: Int) throws -> Array<UInt8> {
101→    let range = reader.offset..<(reader.offset+count)
102→    guard reader.data.count >= range.upperBound else {
103→        throw UniffiInternalError.bufferOverflow
104→    }
105→    var value = [UInt8](repeating: 0, count: count)
106→    value.withUnsafeMutableBufferPointer({ buffer in
107→        reader.data.copyBytes(to: buffer, from: range)
108→    })
109→    reader.offset = range.upperBound
110→    return value
111→}
