255→pub async fn fetch_today_sessions(
256→    base_url: String,
257→    token: String,
258→    timezone: String,
259→) -> Result<Vec<Session>, PabloError> {
260→    Compat::new(async move {
261→        let client = ApiClient::new(base_url);
262→        let token = SecretString::from(token);
263→
264→        let response = client
265→            .get("/api/sessions/today", &token)
266→            .query(&[("timezone", &timezone)])
267→            .send()
268→            .await
269→            .map_err(|e| PabloError::ApiClient {
270→                status_code: 0,
271→                message: e.to_string(),
272→            })?;
273→
274→        if !response.status().is_success() {
275→            return Err(handle_error_response(response).await);
276→        }
277→
278→        let list = response
279→            .json::<SessionListResponse>()
280→            .await
281→            .map_err(|e| PabloError::JsonParse {
282→                message: e.to_string(),
283→            })?;
284→        Ok(list.data)
285→    })
286→    .await
287→}
