    "Companion",
    "Calendar",
};

enum QualityPreset {
    "Fast",
    "Balanced",
    "Accurate",
};

// Minimal patient info embedded in a session.
dictionary PatientSummary {
    string id;
    string first_name;
    string last_name;
};

// A therapy session.
dictionary Session {
    string id;
    string patient_id;
    PatientSummary? patient;
    SessionStatus status;
    string? scheduled_at;
    string? started_at;
    string? ended_at;
    u32? duration_minutes;
    string? video_link;
    VideoPlatform? video_platform;
    SessionType? session_type;
    SessionSource? source;
    string? notes;
    string created_at;
    string updated_at;
};

// Request body for creating a new session.
dictionary CreateSessionRequest {
    string patient_id;
    string scheduled_at;
    u32? duration_minutes;
    string? video_link;
    VideoPlatform? video_platform;
    SessionType? session_type;
    SessionSource? source;
    string? notes;
};

// Request body for updating an existing session.
dictionary UpdateSessionRequest {
    string? scheduled_at;
    string? video_link;
    VideoPlatform? video_platform;
    u32? duration_minutes;
    string? notes;
};

// Therapist preference settings.
dictionary UserPreferences {
    VideoPlatform default_video_platform;
    SessionType default_session_type;
    u32 default_duration_minutes;
    boolean auto_transcribe;
    QualityPreset quality_preset;
    string therapist_display_name;
};

// User profile from the Pablo backend.
dictionary UserProfile {
    string id;
    string email;
    string first_name;
    string last_name;
    string role;
    string created_at;
};

// BAA acceptance status.
dictionary BaaStatus {
